{"content":"1: #include "source/common/config/type_to_endpoint.h"
2: 
3: #include "envoy/annotations/resource.pb.h"
4: 
5: #include "source/common/grpc/common.h"
6: 
7: // API_NO_BOOST_FILE
8: 
9: namespace Envoy {
10: namespace Config {
11: 
12: namespace {
13: 
14: // A service's name, e.g. "envoy.api.v2.RouteDiscoveryService",
15: // "envoy.service.route.v3.RouteDiscoveryService".
16: using ServiceName = std::string;
17: 
18: // A resource type URL. For example: "type.googleapis.com/envoy.api.v2.RouteConfiguration".
19: using TypeUrl = std::string;
20: 
21: TypeUrl getResourceTypeUrl(absl::string_view service_name) {
22:   const auto* service_desc = Protobuf::DescriptorPool::generated_pool()->FindServiceByName(
23:       static_cast<ServiceName>(service_name));
24:   ASSERT(service_desc != nullptr, fmt::format("{} missing", service_name));
25:   ASSERT(service_desc->options().HasExtension(envoy::annotations::resource));
26: 
27:   return Grpc::Common::typeUrl(
28:       service_desc->options().GetExtension(envoy::annotations::resource).type());
29: }
30: 
31: // A method name, e.g. "envoy.api.v2.RouteDiscoveryService.StreamRoutes".
32: using MethodName = std::string;
33: 
34: // This holds  discovery types.
35: struct V3Service {
36:   MethodName sotw_grpc_;
37:   MethodName delta_grpc_;
38:   MethodName rest_;
39: };
40: 
41: using TypeUrlToV3ServiceMap = absl::flat_hash_map<TypeUrl, V3Service>;
42: 
43: TypeUrlToV3ServiceMap* buildTypeUrlToServiceMap() {
44:   auto* type_url_to_versioned_service_map = new TypeUrlToV3ServiceMap();
45: 
46:   // This happens once in the lifetime of Envoy. We build a reverse map from resource type URL to
47:   // service methods (versioned by transport_api_version). We explicitly enumerate all services,
48:   // since DescriptorPool doesn't support iterating over all descriptors, due its lazy load design,
49:   // see https://www.mail-archive.com/protobuf@googlegroups.com/msg04540.html.
50:   for (absl::string_view name : {
51:            "envoy.service.route.v3.RouteDiscoveryService",
52:            "envoy.service.route.v3.ScopedRoutesDiscoveryService",
53:            "envoy.service.route.v3.ScopedRoutesDiscoveryService",
54:            "envoy.service.route.v3.VirtualHostDiscoveryService",
55:            "envoy.service.secret.v3.SecretDiscoveryService",
56:            "envoy.service.cluster.v3.ClusterDiscoveryService",
57:            "envoy.service.endpoint.v3.EndpointDiscoveryService",
58:            "envoy.service.endpoint.v3.LocalityEndpointDiscoveryService",
59:            "envoy.service.listener.v3.ListenerDiscoveryService",
60:            "envoy.service.runtime.v3.RuntimeDiscoveryService",
61:            "envoy.service.extension.v3.ExtensionConfigDiscoveryService",
62:        }) {
63:     const TypeUrl resource_type_url = getResourceTypeUrl(name);
64:     V3Service& service = (*type_url_to_versioned_service_map)[resource_type_url];
65: 
66:     const auto* service_desc =
67:         Protobuf::DescriptorPool::generated_pool()->FindServiceByName(std::string(name));
68:     ASSERT(service_desc != nullptr, fmt::format("{} missing", name));
69:     ASSERT(service_desc->options().HasExtension(envoy::annotations::resource));
70: 
71:     // We populate the service methods that are known below, but it's possible that some
72:     // services don't implement all, e.g. VHDS doesn't support SotW or REST.
73:     for (int method_index = 0; method_index < service_desc->method_count(); ++method_index) {
74:       const auto& method_desc = *service_desc->method(method_index);
75:       if (absl::StartsWith(method_desc.name(), "Stream")) {
76:         service.sotw_grpc_ = method_desc.full_name();
77:       } else if (absl::StartsWith(method_desc.name(), "Delta")) {
78:         service.delta_grpc_ = method_desc.full_name();
79:       } else if (absl::StartsWith(method_desc.name(), "Fetch")) {
80:         service.rest_ = method_desc.full_name();
81:       } else {
82:         ASSERT(false, "Unknown xDS service method");
83:       }
84:     }
85:   }
86:   return type_url_to_versioned_service_map;
87: }
88: 
89: TypeUrlToV3ServiceMap& typeUrlToV3ServiceMap() {
90:   static TypeUrlToV3ServiceMap* type_url_to_versioned_service_map = buildTypeUrlToServiceMap();
91:   return *type_url_to_versioned_service_map;
92: }
93: 
94: } // namespace
95: 
96: const Protobuf::MethodDescriptor& deltaGrpcMethod(absl::string_view type_url) {
97:   const auto it = typeUrlToV3ServiceMap().find(static_cast<TypeUrl>(type_url));
98:   ASSERT(it != typeUrlToV3ServiceMap().cend());
99:   return *Protobuf::DescriptorPool::generated_pool()->FindMethodByName(it->second.delta_grpc_);
100: }
101: 
102: const Protobuf::MethodDescriptor& sotwGrpcMethod(absl::string_view type_url) {
103:   const auto it = typeUrlToV3ServiceMap().find(static_cast<TypeUrl>(type_url));
104:   ASSERT(it != typeUrlToV3ServiceMap().cend());
105:   return *Protobuf::DescriptorPool::generated_pool()->FindMethodByName(it->second.sotw_grpc_);
106: }
107: 
108: const Protobuf::MethodDescriptor& restMethod(absl::string_view type_url) {
109:   const auto it = typeUrlToV3ServiceMap().find(static_cast<TypeUrl>(type_url));
110:   ASSERT(it != typeUrlToV3ServiceMap().cend());
111:   return *Protobuf::DescriptorPool::generated_pool()->FindMethodByName(it->second.rest_);
112: }
113: 
114: } // namespace Config
115: } // namespace Envoy
