38: // Returns true if `resource_name` contains the wildcard XdsTp resource, for example:
39: // xdstp://test/envoy.config.cluster.v3.Cluster/foo-cluster/*
40: // xdstp://test/envoy.config.cluster.v3.Cluster/foo-cluster/*?node.name=my_node
41: bool isXdsTpWildcard(const std::string& resource_name) {
42:   return XdsResourceIdentifier::hasXdsTpScheme(resource_name) &&
43:          (absl::EndsWith(resource_name, "/*") || absl::StrContains(resource_name, "/*?"));
44: }
45: 
46: // Converts the XdsTp resource name to its wildcard equivalent.
47: // Must only be called on XdsTp resource names.
48: std::string convertToWildcard(const std::string& resource_name) {
49:   ASSERT(XdsResourceIdentifier::hasXdsTpScheme(resource_name));
50:   auto resource_or_error = XdsResourceIdentifier::decodeUrn(resource_name);
51:   THROW_IF_STATUS_NOT_OK(resource_or_error, throw);
52:   xds::core::v3::ResourceName xdstp_resource = resource_or_error.value();
53:   const auto pos = xdstp_resource.id().find_last_of('/');
54:   xdstp_resource.set_id(
55:       pos == std::string::npos ? "*" : absl::StrCat(xdstp_resource.id().substr(0, pos), "/*"));
56:   XdsResourceIdentifier::EncodeOptions options;
57:   options.sort_context_params_ = true;
58:   return XdsResourceIdentifier::encodeUrn(xdstp_resource, options);
59: }
