20: std::string Utility::truncateGrpcStatusMessage(absl::string_view error_message) {
21:   // GRPC sends error message via trailers, which by default has a 8KB size limit(see
22:   // https://github.com/grpc/grpc/blob/master/doc/PROTOCOL-HTTP2.md#requests). Truncates the
23:   // error message if it's too long.
24:   constexpr uint32_t kProtobufErrMsgLen = 4096;
25:   return fmt::format("{}{}", error_message.substr(0, kProtobufErrMsgLen),
26:                      error_message.length() > kProtobufErrMsgLen ? "...(truncated)" : "");
27: }
