70: /**
71:  * Check the grpc_services and cluster_names for API config sanity. Throws on error.
72:  * @param api_config_source the config source to validate.
73:  * @param max_grpc_services the maximal number of grpc services allowed.
74:  * @return an invalid status when an API config has the wrong number of gRPC
75:  * services or cluster names, depending on expectations set by its API type.
76:  */
77: absl::Status
78: checkApiConfigSourceNames(const envoy::config::core::v3::ApiConfigSource& api_config_source,
79:                           int max_grpc_services) {
80:   const bool is_grpc =
81:       (api_config_source.api_type() == envoy::config::core::v3::ApiConfigSource::GRPC ||
82:        api_config_source.api_type() == envoy::config::core::v3::ApiConfigSource::DELTA_GRPC);
83: 
84:   if (api_config_source.cluster_names().empty() && api_config_source.grpc_services().empty()) {
85:     return absl::InvalidArgumentError(
86:         fmt::format("API configs must have either a gRPC service or a cluster name defined: {}",
87:                     api_config_source.DebugString()));
88:   }
89: 
90:   if (is_grpc) {
91:     if (!api_config_source.cluster_names().empty()) {
92:       return absl::InvalidArgumentError(
93:           fmt::format("{}::(DELTA_)GRPC must not have a cluster name specified: {}",
94:                       api_config_source.GetTypeName(), api_config_source.DebugString()));
95:     }
96:     if (api_config_source.grpc_services_size() > max_grpc_services) {
97:       return absl::InvalidArgumentError(fmt::format(
98:           "{}::(DELTA_)GRPC must have no more than {} gRPC services specified: {}",
99:           api_config_source.GetTypeName(), max_grpc_services, api_config_source.DebugString()));
100:     }
