26: absl::StatusOr<SubscriptionPtr> SubscriptionFactoryImpl::subscriptionFromConfigSource(
27:     const envoy::config::core::v3::ConfigSource& config, absl::string_view type_url,
28:     Stats::Scope& scope, SubscriptionCallbacks& callbacks,
29:     OpaqueResourceDecoderSharedPtr resource_decoder, const SubscriptionOptions& options) {
30:   RETURN_IF_NOT_OK(Config::Utility::checkLocalInfo(type_url, local_info_));
31:   SubscriptionStats stats = Utility::generateStats(scope);
32: 
33:   std::string subscription_type = "";
34:   ConfigSubscriptionFactory::SubscriptionData data{local_info_,
35:                                                    dispatcher_,
36:                                                    cm_,
37:                                                    validation_visitor_,
38:                                                    api_,
39:                                                    server_,
40:                                                    xds_resources_delegate_,
41:                                                    xds_config_tracker_,
42:                                                    config,
43:                                                    type_url,
44:                                                    scope,
45:                                                    callbacks,
46:                                                    resource_decoder,
47:                                                    options,
48:                                                    absl::nullopt,
49:                                                    stats};
50: 
51:   switch (config.config_source_specifier_case()) {
52:   case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kPath: {
53:     RETURN_IF_NOT_OK(Utility::checkFilesystemSubscriptionBackingPath(config.path(), api_));
54:     subscription_type = "envoy.config_subscription.filesystem";
55:     break;
56:   }
57:   case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kPathConfigSource: {
58:     RETURN_IF_NOT_OK(
59:         Utility::checkFilesystemSubscriptionBackingPath(config.path_config_source().path(), api_));
60:     subscription_type = "envoy.config_subscription.filesystem";
61:     break;
62:   }
63:   case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kApiConfigSource: {
64:     const envoy::config::core::v3::ApiConfigSource& api_config_source = config.api_config_source();
65:     RETURN_IF_NOT_OK(Utility::checkApiConfigSourceSubscriptionBackingCluster(cm_.primaryClusters(),
66:                                                                              api_config_source));
67:     RETURN_IF_NOT_OK(Utility::checkTransportVersion(api_config_source));
68:     switch (api_config_source.api_type()) {
69:       PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;
70:     case envoy::config::core::v3::ApiConfigSource::AGGREGATED_GRPC:
71:       return absl::InvalidArgumentError("Unsupported config source AGGREGATED_GRPC");
72:     case envoy::config::core::v3::ApiConfigSource::AGGREGATED_DELTA_GRPC:
73:       return absl::InvalidArgumentError("Unsupported config source AGGREGATED_DELTA_GRPC");
74:     case envoy::config::core::v3::ApiConfigSource::DEPRECATED_AND_UNAVAILABLE_DO_NOT_USE:
75:       return absl::InvalidArgumentError(
76:           "REST_LEGACY no longer a supported ApiConfigSource. "
77:           "Please specify an explicit supported api_type in the following config:\n" +
78:           config.DebugString());
79:     case envoy::config::core::v3::ApiConfigSource::REST:
80:       subscription_type = "envoy.config_subscription.rest";
81:       break;
82:     case envoy::config::core::v3::ApiConfigSource::GRPC:
83:       subscription_type = "envoy.config_subscription.grpc";
84:       break;
85:     case envoy::config::core::v3::ApiConfigSource::DELTA_GRPC:
86:       subscription_type = "envoy.config_subscription.delta_grpc";
87:       break;
88:     }
89:     if (subscription_type.empty()) {
90:       return absl::InvalidArgumentError("Invalid API config source API type");
91:     }
92:     break;
93:   }
94:   case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kAds: {
95:     subscription_type = "envoy.config_subscription.ads";
96:     break;
97:   }
98:   default:
99:     return absl::InvalidArgumentError(
100:         "Missing config source specifier in envoy::config::core::v3::ConfigSource");
101:   }
102:   ConfigSubscriptionFactory* factory =
103:       Registry::FactoryRegistry<ConfigSubscriptionFactory>::getFactory(subscription_type);
104:   if (factory == nullptr) {
105:     return absl::InvalidArgumentError(fmt::format(
106:         "Didn't find a registered config subscription factory implementation for name: '{}'",
107:         subscription_type));
108:   }
109:   return factory->create(data);
110: }
