124: absl::StatusOr<SubscriptionPtr> SubscriptionFactoryImpl::collectionSubscriptionFromUrl(
125:     const xds::core::v3::ResourceLocator& collection_locator,
126:     const envoy::config::core::v3::ConfigSource& config, absl::string_view resource_type,
127:     Stats::Scope& scope, SubscriptionCallbacks& callbacks,
128:     OpaqueResourceDecoderSharedPtr resource_decoder) {
129:   SubscriptionStats stats = Utility::generateStats(scope);
130:   SubscriptionOptions options;
131:   envoy::config::core::v3::ConfigSource factory_config = config;
132:   ConfigSubscriptionFactory::SubscriptionData data{local_info_,
133:                                                    dispatcher_,
134:                                                    cm_,
135:                                                    validation_visitor_,
136:                                                    api_,
137:                                                    server_,
138:                                                    xds_resources_delegate_,
139:                                                    xds_config_tracker_,
140:                                                    factory_config,
141:                                                    "",
142:                                                    scope,
143:                                                    callbacks,
144:                                                    resource_decoder,
145:                                                    options,
146:                                                    {collection_locator},
147:                                                    stats};
148:   switch (collection_locator.scheme()) {
149:   case xds::core::v3::ResourceLocator::FILE: {
150:     const std::string path = Http::Utility::localPathFromFilePath(collection_locator.id());
151:     RETURN_IF_NOT_OK(Utility::checkFilesystemSubscriptionBackingPath(path, api_));
152:     factory_config.set_path(path);
153:     auto ptr_or_error = createFromFactory(data, "envoy.config_subscription.filesystem_collection");
154:     RETURN_IF_NOT_OK(ptr_or_error.status());
155:     return std::move(ptr_or_error.value());
156:   }
157:   case xds::core::v3::ResourceLocator::XDSTP: {
158:     if (resource_type != collection_locator.resource_type()) {
159:       return absl::InvalidArgumentError(
160:           fmt::format("xdstp:// type does not match {} in {}", resource_type,
161:                       Config::XdsResourceIdentifier::encodeUrl(collection_locator)));
162:     }
163:     switch (config.config_source_specifier_case()) {
164:     case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kApiConfigSource: {
165:       const envoy::config::core::v3::ApiConfigSource& api_config_source =
166:           config.api_config_source();
167:       RETURN_IF_NOT_OK(Utility::checkApiConfigSourceSubscriptionBackingCluster(
168:           cm_.primaryClusters(), api_config_source));
169:       // All Envoy collections currently are xDS resource graph roots and require node context
170:       // parameters.
171:       options.add_xdstp_node_context_params_ = true;
172:       switch (api_config_source.api_type()) {
173:       case envoy::config::core::v3::ApiConfigSource::DELTA_GRPC: {
174:         std::string type_url = TypeUtil::descriptorFullNameToTypeUrl(resource_type);
175:         data.type_url_ = type_url;
176:         auto ptr_or_error =
177:             createFromFactory(data, "envoy.config_subscription.delta_grpc_collection");
178:         RETURN_IF_NOT_OK(ptr_or_error.status());
179:         return std::move(ptr_or_error.value());
180:       }
181:       case envoy::config::core::v3::ApiConfigSource::AGGREGATED_GRPC:
182:         FALLTHRU;
183:       case envoy::config::core::v3::ApiConfigSource::AGGREGATED_DELTA_GRPC: {
184:         auto ptr_or_error =
185:             createFromFactory(data, "envoy.config_subscription.aggregated_grpc_collection");
186:         RETURN_IF_NOT_OK(ptr_or_error.status());
187:         return std::move(ptr_or_error.value());
188:       }
189:       default:
190:         return absl::InvalidArgumentError(fmt::format("Unknown xdstp:// transport API type in {}",
191:                                                       api_config_source.DebugString()));
192:       }
193:     }
194:     case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kAds: {
195:       // TODO(adisuissa): verify that the ADS is set up in delta-xDS mode.
196:       // All Envoy collections currently are xDS resource graph roots and require node context
197:       // parameters.
198:       options.add_xdstp_node_context_params_ = true;
199:       auto ptr_or_error = createFromFactory(data, "envoy.config_subscription.ads_collection");
200:       RETURN_IF_NOT_OK(ptr_or_error.status());
201:       return std::move(ptr_or_error.value());
202:     }
203:     default:
204:       return absl::InvalidArgumentError(
205:           "Missing or not supported config source specifier in "
206:           "envoy::config::core::v3::ConfigSource for a collection. Only ADS and "
207:           "gRPC in delta-xDS mode are supported.");
208:     }
209:   }
210:   default:
211:     // TODO(htuch): Implement HTTP semantics for collection ResourceLocators.
212:     return absl::InvalidArgumentError("Unsupported code path");
213:   }
214: }
