120:   // Stats prefix for the dns filter
121:   const std::string DNS_FILTER_PREFIX = "envoy.dns_filter_prefix";
122:   // Stats prefix for the Connection limit filter
123:   const std::string CONNECTION_LIMIT_PREFIX = "envoy.connection_limit_prefix";
124:   // Stats prefix for the RBAC network filter
125:   const std::string RBAC_PREFIX = "envoy.rbac_prefix";
126:   // Stats prefix for the RBAC http filter
127:   const std::string RBAC_HTTP_PREFIX = "envoy.rbac_http_prefix";
128:   // Policy name for the RBAC http filter
129:   const std::string RBAC_POLICY_NAME = "envoy.rbac_policy_name";
130:   // Stats prefix for the TCP Proxy network filter
131:   const std::string TCP_PREFIX = "envoy.tcp_prefix";
132:   // Stats prefix for the UDP Proxy network filter
133:   const std::string UDP_PREFIX = "envoy.udp_prefix";
134:   // Downstream cluster for the Fault http filter
135:   const std::string FAULT_DOWNSTREAM_CLUSTER = "envoy.fault_downstream_cluster";
136:   // Operation name for the Dynamo http filter
137:   const std::string DYNAMO_OPERATION = "envoy.dynamo_operation";
138:   // Table name for the Dynamo http filter
139:   const std::string DYNAMO_TABLE = "envoy.dynamo_table";
140:   // Partition ID for the Dynamo http filter
141:   const std::string DYNAMO_PARTITION_ID = "envoy.dynamo_partition_id";
142:   // Request service name GRPC Bridge http filter
143:   const std::string GRPC_BRIDGE_SERVICE = "envoy.grpc_bridge_service";
144:   // Request method name for the GRPC Bridge http filter
